SELECT DRIVES.Department, DRIVES.EqType, DRIVES.EqSeq, Left([DRIVES]![Suffix],1) AS Suffix, [MaineQ]![Department] & [MaineQ]![EqType] & [MaineQ]![EqSeq] & "-" & [Drives]![Suffix] AS Pos, DRIVES.[Control system], DRIVES.Cde, MAINEQ.ReferenceDWG, MAINEQ.OldPOS, MAINEQ.EqNameEn, MAINEQ.eqName26, DRIVES.P_req_kW, DRIVES.Selected_P_kW, DRIVES.Rpm, DRIVES.MaxRpm, DRIVES.MinRpm, DRIVES.RatedCurr, DRIVES.CosinePhi, DRIVES.TorqueNm, DRIVES.Control, DRIVES.MountType, DRIVES.MotorManuf, DRIVES.MotorType, DRIVES.[MotorType-ext], DRIVES.[No], DRIVES.Supplier, DRIVES.Enclosure, DRIVES.NoteUI AS [Note], IIf(IsNull([RevMotList]),Null,IIf(InStr([RevMotList]," ")=0,[revmotlist],Left([RevMotList],InStr([RevMotList]," ")-1))) AS Rev, DRIVES.Voltage, DRIVES.UPS_Voltage, DRIVES.ConstructionType, DRIVES.DriveType, MAINEQ.Deleted, IIf([DRIVES]![deleted]=0,"","Yes") AS Del, DRIVES.PT100_Winding, DRIVES.PT100_Bearing, DRIVES.PTC_Term, DRIVES.Hz
FROM MAINEQ INNER JOIN (DRIVES LEFT JOIN MotorData ON DRIVES.MotorTypeID = MotorData.ID) ON (MAINEQ.Eqseq = DRIVES.EqSeq) AND (MAINEQ.EqType = DRIVES.EqType) AND (MAINEQ.Department = DRIVES.Department)
WHERE (((DRIVES.Department) Like "SO*"))
ORDER BY DRIVES.Department, DRIVES.EqType, DRIVES.EqSeq, Left([DRIVES]![Suffix],1);
